#!/usr/bin/env node
// Validates that all required circuit artifacts exist before building.
// These are generated by `nargo compile` in packages/circuits/.

const fs = require('fs');
const path = require('path');

const CIRCUITS_DIR = path.resolve(__dirname, '../../circuits');
const REQUIRED = ['deposit', 'shielded_transfer', 'withdraw', 'anonymous_swap'];

let missing = false;

for (const circuit of REQUIRED) {
  const artifactPath = path.join(CIRCUITS_DIR, circuit, 'target', `${circuit}.json`);
  if (!fs.existsSync(artifactPath)) {
    console.error(`[ERROR] Missing circuit artifact: ${artifactPath}`);
    console.error(`        Run: cd packages/circuits/${circuit} && nargo compile`);
    missing = true;
  }
}

if (missing) {
  console.error('\n[FATAL] Circuit artifacts not found. Build all circuits first:');
  console.error('        cd packages/circuits && for d in */; do (cd "$d" && nargo compile); done\n');
  process.exit(1);
}

console.log(`[OK] All ${REQUIRED.length} circuit artifacts found`);
